<template><div class="page"><h2>TTS 转换</h2><div class="grid grid-2"><div class="card"><el-form label-position="top"><el-form-item label="选择声音"><el-select class="full" v-model="form.voiceModelId"><el-option v-for="v in voices" :key="v.id" :label="v.name+'（'+v.status+'）'" :value="v.id"/></el-select></el-form-item><el-form-item label="文本"><el-input v-model="form.text" type="textarea" :rows="8" maxlength="500" show-word-limit/></el-form-item><el-form-item label="语速"><el-slider v-model="form.speed" :min="0.5" :max="2" :step="0.1" show-input/></el-form-item><el-form-item label="音调"><el-slider v-model="form.pitch" :min="0.5" :max="2" :step="0.1" show-input/></el-form-item><el-button type="primary" :loading="loading" @click="convert">合成语音</el-button></el-form></div><div class="card"><h3>播放结果</h3><audio v-if="audioUrl" :src="audioUrl" controls class="full"></audio><el-empty v-else description="暂无合成结果"/><h3>历史记录</h3><div v-for="h in history" :key="h.id||h.taskId" class="history-item"><div>{{h.textContent||h.text||'TTS任务'}} </div><small class="muted">{{h.createdAt||h.status}}</small><br/><el-button size="small" @click="download(h.id||h.taskId)">下载</el-button></div></div></div></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList } from '../api/voice';import { convertTTS,getTTSHistory,downloadTTS } from '../api/tts';const voices=ref([]),history=ref([]),audioUrl=ref(''),loading=ref(false);const form=reactive({voiceModelId:null,text:'大家好，欢迎来到我的直播间',speed:1,pitch:1});async function init(){voices.value=await getVoiceList()||[];history.value=await getTTSHistory().catch(()=>[])||[]}async function convert(){if(!form.voiceModelId||!form.text)return ElMessage.warning('请选择声音并输入文本');loading.value=true;try{const d=await convertTTS(form);audioUrl.value=d.audioUrl||`/api/tts/download/${d.taskId}`;ElMessage.success('合成完成');init()}finally{loading.value=false}}async function download(taskId){const blob=await downloadTTS(taskId);const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`tts_${taskId}.wav`;a.click();URL.revokeObjectURL(url)}onMounted(init)</script>
